+/// Write a DataFrame to an Excel (.xlsx) file.
+///
+/// Matches `pd.DataFrame.to_excel(path)`.
+pub fn write_excel(frame: &DataFrame, path: &Path) -> Result<(), IoError> {
+    let bytes = write_excel_bytes(frame)?;
+    std::fs::write(path, bytes)?;
+    Ok(())
+}
